patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 394dfca262e1..aa7ce16d150c 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -3714,6 +3714,22 @@ Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {
   if (Instruction *Mul = foldSelectZeroOrMul(SI, *this))
     return Mul;

+  // select C2, (select C1, A, B), (select C1, B, A) -> select (xor C1, C2), B, A
+  if (auto *TISel = dyn_cast<SelectInst>(TrueVal))
+    if (auto *FISel = dyn_cast<SelectInst>(FalseVal))
+      if (TISel->getCondition() == FISel->getCondition() &&
+          TISel->hasOneUse() && FISel->hasOneUse()) {
+        Value *C1 = TISel->getCondition();
+        Value *A = TISel->getTrueValue();
+        Value *B = TISel->getFalseValue();
+        if (FISel->getTrueValue() == B && FISel->getFalseValue() == A &&
+            C1->getType() == CondVal->getType()) {
+          Value *NewCond = Builder.CreateXor(C1, CondVal, "xor");
+          return replaceInstUsesWith(SI,
+              Builder.CreateSelect(NewCond, B, A, SI.getName()));
+        }
+      }
+
   // Turn (select C, (op X, Y), (op X, Z)) -> (op X, (select C, Y, Z))
   auto *TI = dyn_cast<Instruction>(TrueVal);
   auto *FI = dyn_cast<Instruction>(FalseVal);

